const trigger = $input.first().json;

// Pull brand from consolidatedSpec, normalise to lowercase + trim
const rawBrand = trigger.consolidatedSpec?.brand || null;
const brandKey = rawBrand ? String(rawBrand).toLowerCase().trim() : null;

// Title-case version for display use later ("samsonite" → "Samsonite")
const brandDisplay = rawBrand
  ? String(rawBrand).trim().split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ')
  : null;

return [{
  json: {
    ...trigger,
    brandKey: brandKey,
    brandDisplay: brandDisplay,
  },
}];

// The Merge node gives us one item that contains either the looked-up brand row
// or the newly-appended brand row. Both have { brand, about_brand }.
const merged = $input.first().json;

// Pull everything we need from upstream nodes via .first() (works across merges)
const trigger = $('When Executed by Another Workflow').first().json;
const normalised = $('Normalise Brand').first().json;

const spec = trigger.consolidatedSpec || {};
const imageData = trigger.imageData || [];
const notes = trigger.notes || '';
const submissionId = trigger.submissionId;
const brandDisplay = normalised.brandDisplay;
const aboutBrand = merged.about_brand || '';

// Build a clean image summary the LLM can reason about without drowning in raw JSON
const imageSummary = imageData.map((img, i) => {
  const attrs = img.attributes || {};
  return {
    index: img.index,
    filename: img.filename,
    view: attrs.view,
    shot_type: attrs.shot_type,
    color_visible: attrs.color_visible,
    features_shown: attrs.features_shown || [],
    variant_context: attrs.variant_context,
    has_text_overlay: attrs.has_text_overlay,
    background_type: attrs.background_type,
  };
});

return [{
  json: {
    submissionId: submissionId,
    brandDisplay: brandDisplay,
    aboutBrand: aboutBrand,
    spec: spec,
    imageSummary: imageSummary,
    imageCount: imageSummary.length,
    notes: notes,
  },
}];

const llmOutput = $input.first().json;

// Gemini's response field is typically "text" in Basic LLM Chain
let raw = llmOutput.text || llmOutput.output || llmOutput.response || '';

if (!raw) {
  throw new Error('No text returned from Generate Content node. Got: ' + JSON.stringify(llmOutput));
}

// Strip markdown code fences if Gemini included them
raw = raw.trim();
if (raw.startsWith('```json')) {
  raw = raw.slice(7).trim();
} else if (raw.startsWith('```')) {
  raw = raw.slice(3).trim();
}
if (raw.endsWith('```')) {
  raw = raw.slice(0, -3).trim();
}

// Parse
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('Failed to parse LLM output as JSON: ' + e.message + '\n\nRaw output:\n' + raw);
}

// Validate required fields
const required = ['title', 'short_description', 'long_description', 'meta_title', 'meta_description', 'features', 'tags', 'attributes', 'image_alt_text'];
const missing = required.filter(f => !(f in parsed));
if (missing.length > 0) {
  throw new Error('LLM output missing required fields: ' + missing.join(', '));
}

// Pull through context for the next node
const context = $('Build LLM Context').first().json;

return [{
  json: {
    submissionId: context.submissionId,
    aboutBrand: context.aboutBrand,
    content: parsed,
  },
}];

const input = $input.first().json;
const content = { ...input.content };

// Pull aboutBrand defensively
const aboutBrand = input.aboutBrand 
  || $('Build LLM Context').first().json.aboutBrand 
  || '';

const brandDisplay = $('Normalise Brand').first().json.brandDisplay || 'the brand';

// Append about_brand to long_description
if (aboutBrand && content.long_description) {
  content.long_description = content.long_description.trim() 
    + '\n\nAbout ' + brandDisplay + ':\n\n' 
    + aboutBrand;
}

// Pass variant arrays through directly from spec - no LLM involvement
// This guarantees we never lose sizes/colors that the LLM would otherwise filter
const spec = $('Build LLM Context').first().json.spec || {};
content.available_sizes = Array.isArray(spec.size_options) ? spec.size_options : [];
content.available_colors = Array.isArray(spec.color_options) ? spec.color_options : [];

return [{
  json: {
    submissionId: input.submissionId,
    content: content,
  },
}];
